        "id": 2,
        "device": "router2",
        "action": "show_interface",
        "target": "GigabitEthernet0/0/0",
        "parameters": [
          "status",
          "line-protocol"
        ]
      },
      {
        "id": 3,
        "device": "router1",
        "action": "show_ip_route",
        "target": "172.16.0.0/24",
        "parameters": []
      },
      {
        "id": 4,
        "device": "router2",
        "action": "show_ip_route",
        "target": "172.16.0.0/24",
        "parameters": []
      },
      {
        "id": 5,
        "device": "router1",
        "action": "ping",
